import * as fs from 'fs';
import * as path from 'path';

export async function Notify(message: string): Promise<string> {
  const logDir = '/workspace';
  if (!fs.existsSync(logDir)) {
    fs.mkdirSync(logDir, { recursive: true });
  }
  const logFile = path.join(logDir, 'reminder.log');
  const logMessage = `Notified: ${message}`;
  fs.appendFileSync(logFile, logMessage + '\n');
  return logMessage;
}

import { proxyActivities, sleep } from '@temporalio/workflow';
import type * as activities from './activities';

const { Notify } = proxyActivities<typeof activities>({
  startToCloseTimeout: '1 minute',
});

export async function ReminderWorkflow(input: { message: string; delaySeconds: number }): Promise<string> {
  await sleep(input.delaySeconds * 1000);
  return await Notify(input.message);
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities';

export async function startWorker() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;

  if (!address || !namespace || !apiKey) {
    throw new Error('Missing Temporal Cloud environment variables');
  }

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'reminder-ts',
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  return worker;
}

import { Connection, Client } from '@temporalio/client';
import { ReminderWorkflow } from './workflows';

export async function runClient() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !namespace || !apiKey) {
    throw new Error('Missing Temporal Cloud environment variables');
  }

  if (!runId) {
    throw new Error('Missing ZEALT_RUN_ID environment variable');
  }

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const handle = await client.workflow.start(ReminderWorkflow, {
    taskQueue: 'reminder-ts',
    workflowId: `reminder-${runId}`,
    args: [{ message: 'wake up', delaySeconds: 3 }],
  });

  const result = await handle.result();
  console.log(result);
  return result;
}

import { startWorker } from './worker';
import { runClient } from './client';

async function main() {
  const worker = await startWorker();

  // Start worker in the background
  const workerPromise = worker.run();

  try {
    await runClient();
  } catch (err) {
    console.error('Client error:', err);
    process.exit(1);
  }

  // Once the client is done, we can exit the process
  process.exit(0);
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});
